// In production: pull from Datadog/PagerDuty/StatusPage API
const services = [
  { name: 'ProjectFlow Web App', sla_target_pct: 99.9, uptime_minutes: 10069, total_minutes: 10080, incidents: [{ id: 'INC-089', start: '2026-07-12T08:43:00Z', end: '2026-07-12T09:30:00Z', duration_minutes: 47, severity: 'P0', description: 'Dashboard timeout — enterprise accounts' }] },
  { name: 'ProjectFlow API', sla_target_pct: 99.95, uptime_minutes: 10069, total_minutes: 10080, incidents: [{ id: 'INC-089', start: '2026-07-12T08:43:00Z', end: '2026-07-12T09:30:00Z', duration_minutes: 47, severity: 'P0', description: 'Same root cause as Web App' }] },
  { name: 'Webhook Delivery', sla_target_pct: 99.5, uptime_minutes: 10080, total_minutes: 10080, incidents: [] },
  { name: 'Data Export Service', sla_target_pct: 99.0, uptime_minutes: 10050, total_minutes: 10080, incidents: [{ id: 'INC-090', start: '2026-07-09T14:00:00Z', end: '2026-07-09T14:30:00Z', duration_minutes: 30, severity: 'P2', description: 'CSV export errors after v2.4.0' }] }
];
const period = { start: '2026-07-07', end: '2026-07-13', period_type: 'week' };
return [{ json: { services, period, product: 'ProjectFlow' } }];

const { services, period, product } = $input.first().json;
const results = services.map(s => {
  const uptime_pct = parseFloat(((s.uptime_minutes / s.total_minutes) * 100).toFixed(4));
  const downtime_minutes = s.total_minutes - s.uptime_minutes;
  const sla_met = uptime_pct >= s.sla_target_pct;
  const sla_gap = parseFloat((uptime_pct - s.sla_target_pct).toFixed(4));
  return { name: s.name, uptime_pct, sla_target_pct: s.sla_target_pct, sla_met, sla_gap, downtime_minutes, incident_count: s.incidents.length, incidents: s.incidents };
});
const breached = results.filter(r => !r.sla_met);
const total_incidents = results.reduce((s,r) => s + r.incident_count, 0);
return [{ json: { results, period, product, meta: { service_count: services.length, sla_breaches: breached.length, total_incidents, generated_at: new Date().toISOString() }, breached } }];

const { results, period, product, meta: m, breached } = $input.first().json;
const svcLines = results.map(r => [
  `  [${r.sla_met?'✅ MET':'❌ BREACH'}] ${r.name}: ${r.uptime_pct}% (target ${r.sla_target_pct}%)${!r.sla_met ? ' | gap: '+r.sla_gap+'%' : ''}`,
  `  Downtime: ${r.downtime_minutes}min | Incidents: ${r.incident_count}`,
  ...r.incidents.map(i => `    [${i.severity}] ${i.id}: ${i.description} (${i.duration_minutes}min)`),
  ''
].join('\n')).join('\n');
const report = [
  `UPTIME & SLA REPORT: ${product}`,
  `Period: ${period.start} → ${period.end} | Generated: ${m.generated_at}`,
  `Services: ${m.service_count} | SLA breaches: ${m.sla_breaches} | Incidents: ${m.total_incidents}`,
  ``,
  `SERVICE DETAIL:`,
  svcLines,
  m.sla_breaches > 0 ? `⚠️ SLA BREACH SUMMARY: ${breached.map(b=>b.name).join(', ')} did not meet their uptime targets this period.` : '✅ All services met SLA targets.',
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
